CREATE VIEW `ads_short_video_video_dl_log_v1_view` (`id` COMMENT "自增id", `createtime` COMMENT "创建时间", `appid` COMMENT "应用程序id", `appver` COMMENT "版本号", `chl` COMMENT "渠道值", `mt` COMMENT "终端", `core` COMMENT "corever", `rowdata` COMMENT "行数据", `decryptdata` COMMENT "加密数据", `uniquecdreaderid` COMMENT "唯一id", `currentlanguage` COMMENT "语言id", `sdk` COMMENT "sdk", `regionid` COMMENT "归属区域 id,1:香港,2:北美;", `sr_updatetime` COMMENT "ods同步时间", `sr_createtime` COMMENT "starrocks数据注入时间", `hasopen` COMMENT "客户端上报isOpen,首次打开", `seriesid` COMMENT "拉起短剧id", `defaultdltype` COMMENT "1029上报使用 归因类型 0:DL=0,1: UAC归因 2:IP+UA匹配,3 IP匹配 （归因判断条件就是 sdk=7时候 DefaultDLType 字段类型判断）")
COMMENT "短剧服务端表" AS SELECT `ods`.`ods_tidb_short_video_video_dl_log`.`id`, `ods`.`ods_tidb_short_video_video_dl_log`.`createtime`, `ods`.`ods_tidb_short_video_video_dl_log`.`appid`, `ods`.`ods_tidb_short_video_video_dl_log`.`appver`, `ods`.`ods_tidb_short_video_video_dl_log`.`chl`, `ods`.`ods_tidb_short_video_video_dl_log`.`mt`, `ods`.`ods_tidb_short_video_video_dl_log`.`core`, `ods`.`ods_tidb_short_video_video_dl_log`.`rowdata`, `ods`.`ods_tidb_short_video_video_dl_log`.`decryptdata`, `ods`.`ods_tidb_short_video_video_dl_log`.`uniquecdreaderid`, `ods`.`ods_tidb_short_video_video_dl_log`.`currentlanguage`, `ods`.`ods_tidb_short_video_video_dl_log`.`sdk`, `ods`.`ods_tidb_short_video_video_dl_log`.`regionid`, `ods`.`ods_tidb_short_video_video_dl_log`.`sr_updatetime`, `ods`.`ods_tidb_short_video_video_dl_log`.`sr_createtime`, `ods`.`ods_tidb_short_video_video_dl_log`.`hasopen`, `ods`.`ods_tidb_short_video_video_dl_log`.`seriesid`, `ods`.`ods_tidb_short_video_video_dl_log`.`defaultdltype`
FROM `ods`.`ods_tidb_short_video_video_dl_log`
WHERE (`ods`.`ods_tidb_short_video_video_dl_log`.`HasOpen` = 1) AND (`ods`.`ods_tidb_short_video_video_dl_log`.`SeriesId` IS NOT NULL);